export const CURRICULUM_COURSES = COURSES.filter(c => c.section === "curriculum");
export const SKILLS_COURSES = COURSES.filter(c => c.section === "skills");

export function getCourseById(id: string): Course | undefined {
  return COURSES.find(c => c.id === id || c.slug === id);
}
